package com.cug.geotext.service;
import com.baomidou.mybatisplus.core.conditions.query.LambdaQueryWrapper;import com.cug.geotext.entity.SystemLog;import com.cug.geotext.mapper.SystemLogMapper;import java.time.OffsetDateTime;import java.util.List;import org.springframework.stereotype.Service;
@Service public class SystemLogService{private final SystemLogMapper mapper;public SystemLogService(SystemLogMapper mapper){this.mapper=mapper;}public List<SystemLog>list(String module){LambdaQueryWrapper<SystemLog>w=new LambdaQueryWrapper<SystemLog>().orderByDesc(SystemLog::getCreateTime).last("LIMIT 500");if(module!=null&&!module.isBlank())w.eq(SystemLog::getModule,module);return mapper.selectList(w);}public void record(String module,String action,String method,String path,String status,String error,int elapsed,String provider,String model,String function){SystemLog log=new SystemLog();log.setModule(module);log.setAction(action);log.setRequestMethod(method);log.setRequestPath(path);log.setStatus(status);log.setErrorMessage(error);log.setElapsedMs(elapsed);log.setProvider(provider);log.setModel(model);log.setFunctionName(function);log.setCreateTime(OffsetDateTime.now());mapper.insert(log);}}
